+fn command_group_summary_prefix(group: &str) -> &'static str {
+    match group {
+        "connection" => "Connection-management",
+        "transactions" => "Transaction-control",
+        "sorted_set" => "Sorted-set",
+        _ => {
+            if group.is_empty() {
+                "General"
+            } else {
+                match group {
+                    "string" => "String",
+                    "generic" => "Generic",
+                    "server" => "Server",
+                    "hash" => "Hash",
+                    "list" => "List",
+                    "set" => "Set",
+                    "stream" => "Stream",
+                    "geo" => "Geo",
+                    "bitmap" => "Bitmap",
+                    "hyperloglog" => "HyperLogLog",
+                    "pubsub" => "Pub/sub",
+                    "scripting" => "Scripting",
+                    "cluster" => "Cluster",
+                    _ => "General",
+                }
+            }
+        }
+    }
+}
